import android.app.Application;
import okhttp3.OkHttpClient;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public class AppModule extends Application {
    @Override
    public void onCreate() {
        super.onCreate();

        // Create an OkHttp client with secure transport handling enabled
        OkHttpClient okHttpClient = new OkHttpClient.Builder()
                .sslSocketFactory(TLSUtils.getSslSocketFactory(), TLSUtils.getTrustManager())
                .build();

        // Create a Retrofit instance with the OkHttp client and Gson converter factory
        Retrofit retrofit = new Retrofit.Builder()
                .baseUrl("https://api.example.com/users")
                .client(okHttpClient)
                .addConverterFactory(GsonConverterFactory.create())
                .build();

        // Create a REST client for the API
        UserApi userApi = retrofit.create(UserApi.class);
    }
}